from cryptography.fernet import Fernet

# Generate and save the encryption key securely
def generate_key():
    key = Fernet.generate_key()
    with open("secret.key", "wb") as key_file:
        key_file.write(key)

# Load the encryption key from file
def load_key():
    return open("secret.key", "rb").read()

# Encrypt a credit card number using the stored key
def encrypt_card_number(card_number):
    key = load_key()
    fernet = Fernet(key)
    encrypted_number = fernet.encrypt(card_number.encode())
    return encrypted_number

# Decrypt a credit card number using the stored key
def decrypt_card_number(encrypted_number):
    key = load_key()
    fernet = Fernet(key)
    decrypted_number = fernet.decrypt(encrypted_number).decode()
    return decrypted_number

